+        let mut session3 = AgentSession::new(
+            agent3,
+            Arc::clone(&session),
+            true,
+            ResolvedCompactionSettings::default(),
+        );
+
+        // Continue without new user message
+        let message3 = session3
+            .agent
+            .run_continue_with_abort(None, |_| {})
+            .await
+            .expect("resume run");
+
+        assert_eq!(
